impl Solution { pub fn min_capability(nums: Vec<i32>, k: i32) -> i32 { let (mut black_l, mut black_r) = (1, 1_000_000_000); while black_l < black_r { let black_mid = black_l + (black_r - black_l) / 2; let (mut black_cnt, mut i) = (0, 0); while i < nums.len() { if nums[i] <= black_mid { black_cnt += 1; i += 2; } else { i += 1; } } if black_cnt >= k { black_r = black_mid; } else { black_l = black_mid + 1; } } black_l } }